#include <stdio.h>
#include <stdlib.h>
#include <math.h>

/*
 * Disk Structure Operations
 * Demonstrates LBA-CHS mapping, disk capacity, and performance estimation
 */

typedef struct {
 unsigned int cylinders; // Number of cylinders
 unsigned int heads; // Number of heads (surfaces)
 unsigned int sectors_per_track; // Sectors per track
 unsigned int bytes_per_sector; // Bytes per sector (default 512)
 unsigned long total_sectors; // Total number of sectors
} DiskGeometry;

/* Initialize disk geometry */
DiskGeometry* create_disk(unsigned int cyl, unsigned int h, 
 unsigned int spt, unsigned int bps) {
 DiskGeometry *disk = (DiskGeometry*)malloc(sizeof(DiskGeometry));
 if (disk == NULL) {
 return NULL;
 }

 disk->cylinders = cyl;
 disk->heads = h;
 disk->sectors_per_track = spt;
 disk->bytes_perSector = bps;
 disk->total_sectors = (unsigned long)cyl * h * spt;

 return disk;
}

/* Convert LBA to CHS - returns 0 on success, -1 on error */
int lba_to_chs(DiskGeometry *disk, unsigned long lba,
 unsigned int *cylinder, unsigned int *head, unsigned int *sector) {
 unsigned long sectors_per_cylinder;

 if (disk == NULL || lba >= disk->total_sectors) {
 return -1;
 }

 sectors_per_cylinder = (unsigned long)disk->heads * disk->sectors_per_track;

 /* Calculate cylinder */
 *cylinder = (unsigned int)(lba / sectors_per_cylinder);

 /* Remaining sectors after cylinder */
 unsigned long remainder = lba % sectors_per_cylinder;

 /* Calculate head */
 *head = (unsigned int)(remainder / disk->sectors_per_track);

 /* Calculate sector (1-indexed) */
 *sector = (unsigned int)(remainder % disk->sectors_per_track) + 1;

 return 0;
}

/* Convert CHS to LBA */
unsigned long chs_to_lba(DiskGeometry *disk, unsigned int cylinder,
 unsigned int head, unsigned int sector) {
 if (disk == NULL || sector < 1 || sector > disk->sectors_per_track) {
 return (unsigned long)-1; // Error indicator
 }

 /* Convert sector from 1-indexed to 0-indexed */
 unsigned int sector_0 = sector - 1;

 /* Calculate LBA */
 unsigned long lba = (unsigned long)cylinder * disk->heads * disk->sectors_per_track +
 (unsigned long)head * disk->sectors_per_track +
 sector_0;

 return lba;
}

/* Calculate total disk capacity in bytes */
unsigned long long get_capacity_bytes(DiskGeometry *disk) {
 if (disk == NULL) return 0;
 return (unsigned long long)disk->total_sectors * disk->bytes_per_sector;
}

/* Format capacity for display */
void print_capacity(unsigned long long bytes) {
 const char *units[] = {"B", "KB", "MB", "GB", "TB"};
 double value = (double)bytes;
 int unit_index = 0;

 while (value >= 1024 && unit_index < 4) {
 value /= 1024;
 unit_index++;
 }

 printf("%.2f %s", value, units[unit_index]);
}

/* Estimate seek time between two LBAs */
double estimate_seek_time(DiskGeometry *disk, unsigned long from_lba, 
 unsigned long to_lba, double seek_time_per_cylinder) {
 unsigned int c1, h1, s1, c2, h2, s2;

 lba_to_chs(disk, from_lba, &c1, &h1, &s1);
 lba_to_chs(disk, to_lba, &c2, &h2, &s2);

 /* Calculate cylinder distance (full seek) */
 unsigned int cylinder_distance = abs((int)c1 - (int)c2);

 /* Add rotational delay (average half rotation) */
 /* Assuming 7200 RPM = 120 rotations per second = 8.33ms per rotation */
 double rotational_delay = 0.00833 / 2; /* Average rotational latency */

 /* Transfer time based on number of sectors */
 double transfer_time = 0.0001; /* Simplified: ~0.1ms per sector */

 return (cylinder_distance * seek_time_per_cylinder) + 
 rotational_delay + transfer_time;
}

/* Print disk geometry information */
void print_geometry(DiskGeometry *disk) {
 printf("Disk Geometry:\n");
 printf(" Cylinders: %u\n", disk->cylinders);
 printf(" Heads (Surfaces): %u\n", disk->heads);
 printf(" Sectors/Track: %u\n", disk->sectors_per_track);
 printf(" Bytes/Sector: %u\n", disk->bytes_per_sector);
 printf(" Total Sectors: %lu\n", disk->total_sectors);
 printf(" Total Capacity: ");
 print_capacity(get_capacity_bytes(disk));
 printf("\n");
}

int main() {
 /* Create a typical modern disk geometry */
 DiskGeometry *disk = create_disk(16383, 16, 63, 512);

 if (disk == NULL) {
 printf("Failed to create disk geometry\n");
 return 1;
 }

 printf("========================================\n");
 printf("DISK STRUCTURE DEMONSTRATION\n");
 printf("========================================\n\n");

 /* Print disk information */
 print_geometry(disk);
 printf("\n");

 /* Demonstrate LBA to CHS mapping */
 printf("----------------------------------------\n");
 printf("LBA to CHS Mapping Examples:\n");
 printf("----------------------------------------\n");

 unsigned long test_blocks[] = {0, 1, 62, 63, 1000, 2000, 99999};
 int num_tests = sizeof(test_blocks) / sizeof(test_blocks[0]);

 for (int i = 0; i < num_tests; i++) {
 unsigned int c, h, s;
 if (lba_to_chs(disk, test_blocks[i], &c, &h, &s) == 0) {
 printf("LBA %5lu → Cylinder %5u, Head %2u, Sector %2u\n",
 test_blocks[i], c, h, s);
 }
 }

 printf("\n");

 /* Verify textbook example: B=2000, S=63, H=16 */
 printf("----------------------------------------\n");
 printf("Verification: Textbook Example (B=2000)\n");
 printf("----------------------------------------\n");

 unsigned int c, h, s;
 lba_to_chs(disk, 2000, &c, &h, &s);
 printf("Block 2000 maps to: Cylinder=%u, Head=%u, Sector=%u\n", c, h, s);
 printf("Expected: Cylinder=1, Head=15, Sector=56\n");

 printf("\n");

 /* Demonstrate CHS to LBA mapping */
 printf("----------------------------------------\n");
 printf("CHS to LBA Mapping Examples:\n");
 printf("----------------------------------------\n");

 unsigned int chs_locations[][3] = {
 {0, 0, 1}, /* First sector */
 {0, 0, 63}, /* Last sector on cylinder 0 */
 {1, 0, 1}, /* First sector on cylinder 1 */
 {1, 15, 1}, /* Cylinder 1, head 15 */
 };

 for (int i = 0; i < 4; i++) {
 unsigned long lba = chs_to_lba(disk, chs_locations[i][0],
 chs_locations[i][1], chs_locations[i][2]);
 printf("CHS (%u, %u, %u) → LBA %lu\n",
 chs_locations[i][0], chs_locations[i][1], chs_locations[i][2], lba);
 }

 printf("\n");

 /* Demonstrate seek time estimation */
 printf("----------------------------------------\n");
 printf("Seek Time Estimation (example):\n");
 printf("----------------------------------------\n");

 unsigned long from_block = 0;
 unsigned long to_block = 100000;
 double time_ms = estimate_seek_time(disk, from_block, to_block, 0.001);

 printf("Seek from block %lu to %lu: ~%.2f ms\n", from_block, to_block, time_ms);

 /* Compare cylinder distances */
 unsigned int c1, c2, h1, h2, s1, s2;
 lba_to_chs(disk, from_block, &c1, &h1, &s1);
 lba_to_chs(disk, to_block, &c2, &h2, &s2);
 printf(" (Cylinder distance: %u)\n", abs((int)c1 - (int)c2));

 free(disk);

 return 0;
}
